const CATEGORY_EMOJIS = {
  electronics: '📱', cars: '🚗', real_estate: '🏠', fashion: '👗',
  furniture: '🛋️', services: '🔧', jobs: '💼', pets: '🐾',
  sports: '⚽', kids: '👶', hobbies: '🎨', agriculture: '🌾',
  food: '🍕', tools: '🔨', general: '📦'
};

/**
 * Get category label (name + emoji) in a specific language
 * @param {string} categoryId - e.g. 'sports'
 * @param {string} lang - e.g. 'ar'
 * @returns {{name: string, emoji: string}}
 */
export function getCategoryLabel(categoryId, lang = 'ar') {
  if (!categoryId) return { name: 'متفرقات', emoji: '📦' };
  const id = categoryId.toLowerCase().replace(/ /g, '_');
  const key = `cat_${id}`;
  const t = CATEGORY_TRANSLATIONS[key];
  const name = t?.[lang] || t?.en || t?.ar || categoryId;
  return { name, emoji: CATEGORY_EMOJIS[id] || '📦' };
}

/**
 * Get subcategory name in a specific language
 * @param {string} categoryId - e.g. 'sports'
 * @param {string} subcategoryId - e.g. 'fishing'
 * @param {string} lang - e.g. 'ar'
 * @returns {string}
 */
export function getSubcategoryLabel(categoryId, subcategoryId, lang = 'ar') {
  if (!categoryId || !subcategoryId) return '';
  const catId = categoryId.toLowerCase().replace(/ /g, '_');
  const subId = subcategoryId.toLowerCase().replace(/ /g, '_');
  const key = `sub_${catId}_${subId}`;
  const t = CATEGORY_TRANSLATIONS[key];
  return t?.[lang] || t?.en || t?.ar || subcategoryId;
}

/**
 * Detect user language from browser or Accept-Language header
 * Falls back to 'ar' (Arabic — primary marketplace language)
 */
export function detectUserLang() {
  if (typeof navigator === 'undefined') return 'ar';
  const lang = navigator.language || navigator.userLanguage || 'ar';
  const code = lang.slice(0, 2).toLowerCase();
  const supported = ['ar', 'en', 'de', 'es', 'tr', 'ru', 'fa'];
  return supported.includes(code) ? code : 'ar';
}
